#include <stdio.h>
#include <stdlib.h>

typedef struct {int reward; int deadline;} Task;

int compareDesc(const void *a, const void *b) {
    const Task *ta = (const Task *)a;
    const Task *tb = (const Task *)b;
    return tb->reward - ta->reward; // descending reward
}

int find(int x, int parent[]) {
    if (parent[x] == x) return x;
    return parent[x] = find(parent[x], parent);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *deadlines = (int*)malloc(sizeof(int)*N);
        int *rewards   = (int*)malloc(sizeof(int)*N);
        for (int i=0;i<N;i++) scanf("%d", &deadlines[i]);
        for (int i=0;i<N;i++) scanf("%d", &rewards[i]);
        Task *tasks = (Task*)malloc(sizeof(Task)*N);
        int maxD = 0;
        for (int i=0;i<N;i++) {
            tasks[i].reward = rewards[i];
            tasks[i].deadline = deadlines[i];
            if (deadlines[i] > maxD) maxD = deadlines[i];
        }
        qsort(tasks, N, sizeof(Task), compareDesc);
        int *parent = (int*)malloc(sizeof(int)*(maxD+1));
        for (int i=0;i<=maxD;i++) parent[i]=i;
        int cnt=0, total=0;
        for (int i=0;i<N;i++) {
            int slot = find(tasks[i].deadline, parent);
            if (slot>0) {
                parent[slot] = find(slot-1, parent);
                cnt++; total += tasks[i].reward;
            }
        }
        printf("%d %d\n", cnt, total);
        free(deadlines); free(rewards); free(tasks); free(parent);
    }
    return 0;
}

