#include <bits/stdc++.h>
using namespace std;

int findSet(int v, vector<int>& parent) {
    if (parent[v]==v) return v;
    return parent[v]=findSet(parent[v], parent);
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> deadline(N), reward(N);
        for(int &d:deadline) cin>>d;
        for(int &r:reward) cin>>r;
        vector<pair<int,int>> tasks(N);
        int maxD=0;
        for(int i=0;i<N;i++){
            tasks[i]={reward[i], deadline[i]};
            maxD=max(maxD, deadline[i]);
        }
        sort(tasks.begin(), tasks.end(), greater<>()); // by reward descending
        vector<int> parent(maxD+1);
        iota(parent.begin(), parent.end(), 0);
        int cnt=0, total=0;
        for(auto &t:tasks){
            int slot=findSet(t.second, parent);
            if(slot>0){
                parent[slot]=findSet(slot-1, parent);
                cnt++; total+=t.first;
            }
        }
        cout<<cnt<<' '<<total<<"\n";
    }
    return 0;
}

