import java.io.*;
import java.util.*;

public class Main {
    private static int find(int x, int[] parent) {
        if (parent[x] == x) return x;
        return parent[x] = find(parent[x], parent);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] deadline = new int[N];
            int[] reward = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) deadline[i] = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) reward[i] = Integer.parseInt(st.nextToken());
            int[][] tasks = new int[N][2]; // {reward, deadline}
            int maxD = 0;
            for (int i = 0; i < N; i++) {
                tasks[i][0] = reward[i];
                tasks[i][1] = deadline[i];
                if (deadline[i] > maxD) maxD = deadline[i];
            }
            Arrays.sort(tasks, (a, b) -> b[0] - a[0]); // descending reward
            int[] parent = new int[maxD + 1];
            for (int i = 0; i <= maxD; i++) parent[i] = i;
            int cnt = 0, total = 0;
            for (int[] t : tasks) {
                int slot = find(t[1], parent);
                if (slot > 0) {
                    parent[slot] = find(slot - 1, parent);
                    cnt++; total += t[0];
                }
            }
            sb.append(cnt).append(' ').append(total).append('\n');
        }
        System.out.print(sb.toString());
    }
}

