const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const deadlines = new Array(N);
  const rewards = new Array(N);
  for (let i = 0; i < N; i++) deadlines[i] = input[idx++];
  for (let i = 0; i < N; i++) rewards[i] = input[idx++];
  const tasks = [];
  let maxD = 0;
  for (let i = 0; i < N; i++) {
    tasks.push([rewards[i], deadlines[i]]);
    if (deadlines[i] > maxD) maxD = deadlines[i];
  }
  tasks.sort((a, b) => b[0] - a[0]); // descending reward
  const parent = new Array(maxD + 1);
  for (let i = 0; i <= maxD; i++) parent[i] = i;
  const find = (x) => {
    if (parent[x] !== x) parent[x] = find(parent[x]);
    return parent[x];
  };
  let cnt = 0, total = 0;
  for (const [r, d] of tasks) {
    let slot = find(d);
    if (slot > 0) {
      parent[slot] = find(slot - 1);
      cnt++; total += r;
    }
  }
  outputs.push(cnt + ' ' + total);
}
console.log(outputs.join('\n'));

